#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline LL Read()
{
	LL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int max(int x,int y){return x>y?x:y;}
const int N=1e5+10,W=5e5+10;int n,w,num[W],a[N];
struct Set
{
	int *fa;inline void Init(int n){rep(0,n-1,i)fa[i]=i;}
	inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
}B[W];
LL t[N];inline void add(int p,int v){while(p<=n)t[p]+=v,p+=(p&-p);}
inline LL qry(int p){LL v=0;while(p)v+=t[p],p^=(p&-p);return v;}
int *pos[W],buf[N*500],*tmp=buf,pp[W];
inline void Solve(int l,int r,int x)
{
	if(x==1)return;//int L,R,Res,Mid;
//	L=0;R=pp[x]-1;Res=pp[x]-1;while(L<=R)pos[x][Mid=(L+R)>>1]>=l?(R=Mid-1,Res=Mid):(L=Mid+1);l=Res;
//	L=0;R=pp[x]-1;Res=0;while(L<=R)pos[x][Mid=(L+R)>>1]<=r?(L=Mid+1,Res=Mid):(R=Mid-1);r=Res;
	l=lower_bound(pos[x],pos[x]+pp[x],l)-pos[x];
  	r=upper_bound(pos[x],pos[x]+pp[x],r)-pos[x]-1;
//	printf("lr :: %d %d\n",l,r);
	if(l>r)return;for(int i=B[x].fnd(l);i<=r;)
	{
		int v=pos[x][i];//printf("pos:: %d\n",v);
		if(a[v]%x==0){int qwq=a[v]/x;add(v,qwq-a[v]);a[v]=qwq;}
		if(i>=r)break;if(a[v]%x==0)i=B[x].fnd(i+1);
		else i=B[x].fa[i]=B[x].fnd(i+1);
	}
	
}
int main()
{
	n=read();int Q=read();
	rep(1,n,i){w=max(w,a[i]=read());++num[a[i]];add(i,a[i]);}
	rep(1,w,i)for(int j=i<<1;j<=w;j+=i)num[i]+=num[j];
	rep(2,w,i)if(num[i])
	{
		pos[i]=tmp;tmp+=num[i]+1;
		B[i].fa=tmp;B[i].Init(num[i]);tmp+=num[i]+1;
	}
	rep(1,n,i)for(int j=1;j*j<=a[i];++j)if(a[i]%j==0)
	{
		if(j!=1)pos[j][pp[j]++]=i;
		if(j*j!=a[i]){int qwq=a[i]/j;pos[qwq][pp[qwq]++]=i;}
	}
//	rep(1,72,i)
//	{
//		printf("%d :: ",i);rep(1,pp[i],j)printf("(%d,%d)",pos[i][j],B[i].fa[j]);puts("");
//	}
	LL lst=0;while(Q--)
	{
		short opt=read();LL l=Read()^lst,r=Read()^lst;
//		if(l>n||r>n||r>l)return 0;
		switch(opt)
		{
			case 1:Solve(l,r,Read()^lst);break;
			case 2:printf("%lld\n",lst=qry(r)-qry(l-1));
		}
	}
}
